import{_ as s,o as a,c as d,ag as n}from"./chunks/framework.ePeAWSvT.js";const e="/images/skill-manual.png",u=JSON.parse('{"title":"스킬이란?","description":"","frontmatter":{},"headers":[],"relativePath":"학습자료/2-스킬개념/2-1-스킬이란.md","filePath":"학습자료/2-스킬개념/2-1-스킬이란.md"}'),i={name:"학습자료/2-스킬개념/2-1-스킬이란.md"};function l(o,t,r,p,h,c){return a(),d("div",null,[...t[0]||(t[0]=[n('<h1 id="스킬이란" tabindex="-1">스킬이란? <a class="header-anchor" href="#스킬이란" aria-label="Permalink to &quot;스킬이란?&quot;">​</a></h1><p>오늘 워크샵의 핵심은 <strong>스킬</strong>입니다. 이것만 제대로 이해하면 나머지는 자연스럽게 따라옵니다.</p><hr><h2 id="스킬이-뭔가요" tabindex="-1">스킬이 뭔가요? <a class="header-anchor" href="#스킬이-뭔가요" aria-label="Permalink to &quot;스킬이 뭔가요?&quot;">​</a></h2><p>Claude Code 공식 사이트의 정의를 빌리면 이렇습니다:</p><blockquote><p>&quot;Skills는 Claude가 할 수 있는 것을 확장합니다. SKILL.md 파일을 작성하고 지침을 포함하면 Claude가 이를 자신의 도구 모음에 추가합니다.&quot;</p></blockquote><p>말이 좀 어렵죠? 쉽게 바꾸면:</p><blockquote><p><strong>&quot;AI에게 주는 업무 매뉴얼. 한 번 만들면 <code>/스킬이름</code> 한 줄로 계속 재사용.&quot;</strong></p></blockquote><p>가장 중요한 포인트는 이겁니다. 스킬은 <strong>코딩이 아닙니다</strong>. 글로 적는 겁니다. &quot;이런 상황에서, 이런 형식으로, 이런 규칙을 지켜서 결과를 만들어줘&quot;라고 글로 적어두면 AI가 그대로 실행합니다.</p><p><img src="'+e+`" alt="스킬은 AI에게 주는 업무 매뉴얼"></p><hr><h2 id="before-after로-체감하기" tabindex="-1">Before / After로 체감하기 <a class="header-anchor" href="#before-after로-체감하기" aria-label="Permalink to &quot;Before / After로 체감하기&quot;">​</a></h2><p>말보다 비교가 빠릅니다. 실제 업무 상황 3가지입니다.</p><table tabindex="0"><thead><tr><th>상황</th><th>스킬 없이 (Before)</th><th>스킬 있으면 (After)</th></tr></thead><tbody><tr><td><strong>이메일 쓸 때</strong></td><td>&quot;존댓말로, 요점 먼저, 3-5문장으로...&quot; 매번 설명</td><td><code>/이메일초안 납품 일정 변경 요청</code> 한 줄 끝</td></tr><tr><td><strong>회의록 정리</strong></td><td>회의 끝나고 30분 동안 수동 정리</td><td><code>/회의록요약</code> → 3분 만에 정리 완료</td></tr><tr><td><strong>주간보고</strong></td><td>매주 금요일마다 형식 고민부터 시작</td><td><code>/주간보고 이번 주 한 일: ...</code> → 바로 완성</td></tr><tr><td><strong>결과 품질</strong></td><td>그날 컨디션에 따라 들쭉날쭉</td><td>항상 같은 형식, 같은 퀄리티</td></tr><tr><td><strong>소요 시간</strong></td><td>매번 10~30분</td><td>매번 1~3분</td></tr></tbody></table><hr><h2 id="스킬의-정체-skill-md-파일" tabindex="-1">스킬의 정체: SKILL.md 파일 <a class="header-anchor" href="#스킬의-정체-skill-md-파일" aria-label="Permalink to &quot;스킬의 정체: SKILL.md 파일&quot;">​</a></h2><p>스킬의 실체는 <strong>SKILL.md라는 텍스트 파일 하나</strong>입니다. 이 파일은 두 부분으로 구성됩니다.</p><h3 id="파일-구조" tabindex="-1">파일 구조 <a class="header-anchor" href="#파일-구조" aria-label="Permalink to &quot;파일 구조&quot;">​</a></h3><ol><li><strong>YAML frontmatter</strong> (<code>---</code> 사이): 스킬의 이름표. 이름과 설명을 적습니다.</li><li><strong>마크다운 본문</strong>: 실제 지침. 입력 형식, 출력 형식, 규칙을 적습니다.</li></ol><h3 id="실제-skill-md-예시" tabindex="-1">실제 SKILL.md 예시 <a class="header-anchor" href="#실제-skill-md-예시" aria-label="Permalink to &quot;실제 SKILL.md 예시&quot;">​</a></h3><p>비개발자도 바로 쓸 수 있는 이메일 초안 스킬입니다.</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">이메일초안</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  비즈니스 이메일 초안을 작성하는 스킬.</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;/이메일초안 [상황]&quot; 또는 &quot;이메일 써줘&quot;로 호출.</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 이메일 초안 작성기</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 입력</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">사용자가 이메일을 보내야 하는 상황을 설명합니다.</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 출력 형식</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">📧 이메일 초안</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">받는 사람</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">상황에서 추론</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">제목</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">간결한 제목</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">본문 3-5문장</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 작성 규칙</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1. 비즈니스 존댓말 사용</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">2. 간결하게 (3-5문장)</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">3. 핵심 정보 빠짐없이 포함</span></span></code></pre></div><h3 id="skill-md-구조-해부" tabindex="-1">SKILL.md 구조 해부 <a class="header-anchor" href="#skill-md-구조-해부" aria-label="Permalink to &quot;SKILL.md 구조 해부&quot;">​</a></h3><table tabindex="0"><thead><tr><th>부분</th><th>역할</th><th>비유</th><th>필수?</th></tr></thead><tbody><tr><td><code>---</code> 사이 (frontmatter)</td><td>이름표</td><td>명함</td><td>권장</td></tr><tr><td><code>name</code></td><td>스킬 이름, <code>/이름</code>으로 호출</td><td>별명</td><td>권장</td></tr><tr><td><code>description</code></td><td>AI가 언제 쓸지 판단하는 설명</td><td>자기소개</td><td>권장</td></tr><tr><td>마크다운 본문</td><td>실제 지침</td><td>업무 매뉴얼 본문</td><td>필수</td></tr></tbody></table><hr><h2 id="스킬이-저장되는-위치" tabindex="-1">스킬이 저장되는 위치 <a class="header-anchor" href="#스킬이-저장되는-위치" aria-label="Permalink to &quot;스킬이 저장되는 위치&quot;">​</a></h2><table tabindex="0"><thead><tr><th>위치</th><th>경로</th><th>적용 범위</th></tr></thead><tbody><tr><td>개인 (글로벌)</td><td><code>~/.claude/skills/스킬이름/SKILL.md</code></td><td>어디서든 사용 가능</td></tr><tr><td>프로젝트</td><td><code>.claude/skills/스킬이름/SKILL.md</code></td><td>이 프로젝트에서만</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">어디에 만들어야 하나요?</p><p>처음에는 <strong>프로젝트 폴더</strong> 안에 만드세요 (<code>.claude/skills/</code>). 자주 쓰는 스킬은 나중에 글로벌(<code>~/.claude/skills/</code>)로 옮기면 됩니다.</p></div><h3 id="설치-위치-시나리오-billing-스킬을-어디에-만들어야-할까" tabindex="-1">설치 위치 시나리오: &quot;billing 스킬을 어디에 만들어야 할까?&quot; <a class="header-anchor" href="#설치-위치-시나리오-billing-스킬을-어디에-만들어야-할까" aria-label="Permalink to &quot;설치 위치 시나리오: &quot;billing 스킬을 어디에 만들어야 할까?&quot;&quot;">​</a></h3><p>예를 들어 회사 청구서를 만드는 <code>billing</code> 스킬이 있다고 합시다.</p><ul><li><strong>A 프로젝트에서만 쓰는 청구서 양식</strong> → <code>.claude/skills/billing/SKILL.md</code> (프로젝트)</li><li><strong>어떤 프로젝트에서든 쓰는 개인 스킬</strong> → <code>~/.claude/skills/billing/SKILL.md</code> (글로벌)</li></ul><div class="warning custom-block"><p class="custom-block-title">잘못된 위치에 설치하면?</p><ul><li><strong>글로벌에 프로젝트 전용 스킬을 설치</strong> → 다른 프로젝트에서 엉뚱한 청구서 양식이 적용되어 혼동</li><li><strong>프로젝트에만 설치</strong> → 다른 프로젝트에서는 이 스킬을 쓸 수 없음</li></ul><p>처음에는 프로젝트에 만들고, 여러 곳에서 필요해지면 글로벌로 옮기세요!</p></div><h3 id="우선순위-규칙" tabindex="-1">우선순위 규칙 <a class="header-anchor" href="#우선순위-규칙" aria-label="Permalink to &quot;우선순위 규칙&quot;">​</a></h3><p>같은 이름의 스킬이 여러 곳에 있으면 어떻게 될까요? Claude Code는 <strong>위에서 아래로</strong> 우선순위를 적용합니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Enterprise (회사 관리자) — 최우선</span></span>
<span class="line"><span>   └── Organization (팀) — 두번째</span></span>
<span class="line"><span>      └── 글로벌 (~/.claude/) — 세번째</span></span>
<span class="line"><span>         └── 프로젝트 (.claude/) — 네번째</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">비개발자를 위한 요약</p><p>대부분의 경우 Enterprise나 Organization은 신경 쓸 필요 없습니다. 우리는 <strong>글로벌</strong>과 <strong>프로젝트</strong> 두 가지만 기억하면 됩니다!</p></div><hr><h2 id="스킬은-어떻게-읽히나요" tabindex="-1">스킬은 어떻게 읽히나요? <a class="header-anchor" href="#스킬은-어떻게-읽히나요" aria-label="Permalink to &quot;스킬은 어떻게 읽히나요?&quot;">​</a></h2><p>스킬이 한 번에 전부 로딩되는 건 아닙니다. Claude Code는 <strong>3단계에 걸쳐 점진적으로</strong> 스킬을 읽습니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1단계: description만 읽음 (가볍게 훑기)</span></span>
<span class="line"><span>      ↓ 관련 있다고 판단하면</span></span>
<span class="line"><span>2단계: SKILL.md 전문 읽음 (지침 파악)</span></span>
<span class="line"><span>      ↓ 실행 시작</span></span>
<span class="line"><span>3단계: 지침대로 작업 수행</span></span></code></pre></div><p>왜 이렇게 나눠서 읽을까요? 스킬이 10개, 20개로 늘어나면 매번 전부 읽기엔 비효율적이기 때문입니다. 그래서 <strong>description(설명)만 먼저 훑어보고</strong>, 지금 요청에 관련된 스킬만 골라서 전문을 읽습니다.</p><table tabindex="0"><thead><tr><th>방식</th><th>매번 드는 비용</th><th>장점</th></tr></thead><tbody><tr><td>매번 프롬프트 입력</td><td>매번 전체 지침 토큰 소비</td><td>유연함</td></tr><tr><td>스킬 사용</td><td>description만 항상 로드 + 필요할 때만 전문 읽음</td><td>효율적, 일관성</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">그래서 description이 중요한 겁니다</p><p>description은 AI가 &quot;이 스킬이 지금 필요한가?&quot;를 판단하는 <strong>유일한 단서</strong>입니다. 여기에 언제 쓰는 스킬인지, 어떤 키워드로 호출하는지를 명확히 적어야 AI가 정확히 골라냅니다.</p></div><hr><h2 id="스킬이-실행되는-흐름" tabindex="-1">스킬이 실행되는 흐름 <a class="header-anchor" href="#스킬이-실행되는-흐름" aria-label="Permalink to &quot;스킬이 실행되는 흐름&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 사용자가 &quot;/이메일초안 납품 일정 변경 요청&quot; 입력</span></span>
<span class="line"><span>          ↓</span></span>
<span class="line"><span>2. Claude Code가 .claude/skills/이메일초안/SKILL.md 찾기</span></span>
<span class="line"><span>          ↓</span></span>
<span class="line"><span>3. SKILL.md 내용을 읽고 지침 따르기</span></span>
<span class="line"><span>          ↓</span></span>
<span class="line"><span>4. 지침대로 이메일 초안 생성!</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">핵심 포인트</p><p>스킬은 두 가지 방법으로 실행됩니다.</p><ol><li><strong>직접 호출</strong>: <code>/이메일초안 상황설명</code> — 내가 직접 부르는 것</li><li><strong>자동 감지</strong>: &quot;이메일 좀 써줘&quot; — AI가 description을 보고 관련 스킬을 자동 적용</li></ol></div><hr><h2 id="좋은-스킬-vs-나쁜-스킬" tabindex="-1">좋은 스킬 vs 나쁜 스킬 <a class="header-anchor" href="#좋은-스킬-vs-나쁜-스킬" aria-label="Permalink to &quot;좋은 스킬 vs 나쁜 스킬&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>좋은 스킬</th><th>나쁜 스킬</th></tr></thead><tbody><tr><td>범위</td><td>딱 한 가지 일만 함</td><td>&quot;뭐든 다 해줘&quot;</td></tr><tr><td>출력 형식</td><td>명확한 형식 지정</td><td>&quot;알아서 해&quot;</td></tr><tr><td>규칙</td><td>구체적 (3-5문장, 존댓말)</td><td>모호한 (&quot;잘 써줘&quot;)</td></tr><tr><td>이름</td><td>짧고 직관적 (이메일초안, 주간보고)</td><td>길고 복잡 (만능AI자동화도구v2)</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">가장 흔한 실수</p><p>&quot;너무 많은 걸 하려고&quot; 하는 것입니다. 처음 스킬은 딱 한 가지 일만 하게 만드세요. 잘 되면 나중에 기능을 추가하면 됩니다.</p></div><hr><h2 id="스킬-말고도-있나요-—-claude-확장-기능-비교" tabindex="-1">스킬 말고도 있나요? — Claude 확장 기능 비교 <a class="header-anchor" href="#스킬-말고도-있나요-—-claude-확장-기능-비교" aria-label="Permalink to &quot;스킬 말고도 있나요? — Claude 확장 기능 비교&quot;">​</a></h2><p>스킬이 Claude Code를 확장하는 유일한 방법은 아닙니다. 전체 그림을 한 번 보고 가겠습니다.</p><table tabindex="0"><thead><tr><th>기능</th><th>무엇인가요?</th><th>비유</th><th>오늘 다루나요?</th></tr></thead><tbody><tr><td><strong>스킬 (Skills)</strong></td><td>AI 업무 매뉴얼 (SKILL.md)</td><td>요리 레시피</td><td>⭐ 핵심!</td></tr><tr><td><strong>CLAUDE.md</strong></td><td>AI의 기억/성격 설정</td><td>직원 명찰</td><td>⭐ 간단히</td></tr><tr><td><strong>MCP</strong></td><td>외부 도구 연결 포트</td><td>USB-C 케이블</td><td>소개만</td></tr><tr><td><strong>서브에이전트</strong></td><td>AI가 부르는 보조 AI</td><td>팀 리더가 부르는 팀원</td><td>-</td></tr><tr><td><strong>커스텀 슬래시 명령</strong></td><td>빠른 동작 단축키</td><td>키보드 단축키</td><td>-</td></tr><tr><td><strong>훅 (Hooks)</strong></td><td>특정 이벤트에 자동 실행</td><td>알람 설정</td><td>-</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">오늘은 스킬에 집중!</p><p>나머지 기능들은 스킬을 마스터한 뒤 자연스럽게 알게 됩니다. 스킬이 Claude Code 확장의 출발점이에요.</p></div><hr><h2 id="더-알고-싶다면-—-공식-문서-링크" tabindex="-1">더 알고 싶다면 — 공식 문서 링크 <a class="header-anchor" href="#더-알고-싶다면-—-공식-문서-링크" aria-label="Permalink to &quot;더 알고 싶다면 — 공식 문서 링크&quot;">​</a></h2><table tabindex="0"><thead><tr><th>주제</th><th>공식 문서</th></tr></thead><tbody><tr><td>Skills</td><td><a href="https://docs.anthropic.com/en/docs/claude-code/skills" target="_blank" rel="noreferrer">https://docs.anthropic.com/en/docs/claude-code/skills</a></td></tr><tr><td>CLAUDE.md</td><td><a href="https://docs.anthropic.com/en/docs/claude-code/memory" target="_blank" rel="noreferrer">https://docs.anthropic.com/en/docs/claude-code/memory</a></td></tr><tr><td>MCP</td><td><a href="https://modelcontextprotocol.io" target="_blank" rel="noreferrer">https://modelcontextprotocol.io</a></td></tr><tr><td>Sub-agents</td><td><a href="https://docs.anthropic.com/en/docs/claude-code/sub-agents" target="_blank" rel="noreferrer">https://docs.anthropic.com/en/docs/claude-code/sub-agents</a></td></tr></tbody></table><hr><h2 id="자가-점검-체크리스트" tabindex="-1">자가 점검 체크리스트 <a class="header-anchor" href="#자가-점검-체크리스트" aria-label="Permalink to &quot;자가 점검 체크리스트&quot;">​</a></h2><ul><li>[ ] 스킬이 뭔지 설명할 수 있다</li><li>[ ] SKILL.md 파일의 구조 (frontmatter + 본문)를 안다</li><li>[ ] 글로벌 vs 프로젝트 스킬 위치 차이를 안다</li><li>[ ] 스킬이 3단계로 읽히는 과정을 안다</li><li>[ ] Claude의 확장 기능 종류를 알고, 오늘 초점이 스킬인 이유를 안다</li></ul><hr><p>다음 단계에서는 공식 스킬을 직접 체험해봅니다!</p><p><strong><a href="/학습자료/2-스킬개념/2-2-공식스킬체험">공식 스킬 체험 →</a></strong></p>`,65)])])}const g=s(i,[["render",l]]);export{u as __pageData,g as default};
